import React, {useState} from "react";
import './Welcome.css';

function Welcome (props) {
    const [userName, setUserName] = useState('');
    const [passWord, setPassWord] = useState('');
    const [isLoginSuccessful, setIsLoginSuccessful] = useState(false);
    const handleUsernameChange = (e) => {
        const value = e.target.value;
        setUserName(value);
    }
    const Login = () => {
        if (setUserName === 'admin' && setPassWord === '1234') {
            setIsLoginSuccessful(true);
        }
        else {
            isLoginSuccessful(false);
        }
}
    const handlePasswordChange = (e) => {
        const value = e.target.value;
        setPassWord(value);
    }
    return  (
    <div>
        <h1 className = 'title'>Welcome to Productiv!</h1>
        <invalidCredentials Login = {setIsLoginSuccessful}></invalidCredentials>
        <form className = 'location-form'>
            <div>
            <label htmlFor="username">Username </label>
            <input type="text" id="username" name="username" value = {userName} onChange = {handleUsernameChange}></input>
            </div>
            <div>
            <label htmlFor="password">Password </label>
            <input type="password" id="password" name="password" value = {passWord} onChange = {handlePasswordChange}></input>
            </div>
            <div>
            <button className ='button' type="submit" value= "Log in" onClick={Login}>Login</button>
            <button className ='button' type="submit" value= "Sign up" onClick={invalidCredentials}>Sign up</button>
            </div>
        </form>
    </div>
    )
    function invalidCredentials (props) {
        if (props.isLoginSuccessful) {
            return <div className="invalid-credentials">Invalid attempt, please confirm your username and password.</div>
        }
    }

}

export default Welcome;
